7	/**
8	 * @ch 除錯工具事件定義
9	 */
10	export const DEBUG_TOOL_EVENT = {
11	    /**@ch GameView 接收到 Spin 資料 - 參數: (data: Uint8Array) */
12	    SPIN_DATA_RECEIVED: "DEBUG_TOOL_EVENT_SPIN_DATA_RECEIVED",
13	
14	    /**@ch GameView 請求取得待用的 Spin 資料 - 參數: (func(spinAck: protocol.ar2es2Proto.ISpinAck) => void) */
15	    GET_PENDING_SPIN_DATA: "DEBUG_TOOL_EVENT_GET_PENDING_SPIN_DATA",
16	
17	    /**@ch GameView 通知已使用待用資料，請求清除 */
18	    CLEAR_PENDING_SPIN_DATA: "DEBUG_TOOL_EVENT_CLEAR_PENDING_SPIN_DATA"
19	}
