21	/**
22	 * @ch 除錯工具管理器
23	 * @description 提供 Spin 資料的下載、上傳、重放等除錯功能
24	 * @note 此工具僅在開發環境下啟用，正式版本會被編譯器移除
25	 */
26	@ccclass('DebugToolManager')
27	export class DebugToolManager extends Component {
28	
29	    /**@ch 啟用除錯功能（只在開發環境生效）*/
30	    private m_enableDebugTools: boolean = true;
31	
32	    /**@ch 最後一次 spin 的原始資料 */
33	    private m_lastSpinData: Uint8Array = null;
34	
35	    /**@ch 待用的除錯 Spin 資料（用於下次 Spin 時替換 Server 資料）*/
36	    private m_pendingSpinData: protocol.ar2es2Proto.ISpinAck = null;
37	
38	    /**@ch 按鍵狀態追蹤 */
39	    private m_isCtrlPressed: boolean = false;
40	    private m_isAltPressed: boolean = false;
41	    private m_isShowProfiler: boolean = false;
42	
43	    //#region 生命週期
44	
45	    onLoad() {
46	        // 只在開發環境且非原生平台時啟用
47	        if (!this.IsDebugEnvironment()) {
48	            this.enabled = false;
49	            return;
50	        }
51	
52	        // 初始化 Profiler 顯示狀態（避免一開始狀態不同步）
53	        this.m_isShowProfiler = this.GetProfilerIsShowing();
54	
55	        this.RegisterKeyboardEvents();
56	        this.RegisterEventListeners();
57	        // this.ExposeToWindow();
58	
59	        log("🛠️ DebugToolManager 已啟用");
60	    }
61	
62	    onDestroy() {
63	        if (this.IsDebugEnvironment()) {
64	            this.UnregisterKeyboardEvents();
65	            this.UnregisterEventListeners();
66	            this.RemoveFromWindow();
67	        }
68	    }
69	
70	    //#endregion 生命週期
71	
72	    //#region 環境檢測
73	
74	    /**
75	     * @ch 檢查是否為除錯環境
76	     * @returns 是否為除錯環境
77	     */
78	    private IsDebugEnvironment(): boolean {
79	        // 只在 Web 環境啟用
80	        const isWebEnvironment = !sys.isNative && typeof window !== 'undefined';
81	
82	        return isWebEnvironment && this.m_enableDebugTools;
83	    }
84	
85	    //#endregion 環境檢測
86	
87	    //#region 視窗暴露
88	
89	    /**
90	     * @ch 暴露到全域 window 物件（使用命名空間避免衝突）
91	     */
92	    private ExposeToWindow(): void {
93	        if (typeof window !== 'undefined') {
94	            // 使用專案特定的命名空間
95	            (window as any)['__EYESTRIKE_DEBUG__'] = this;
96	            log("💡 DebugToolManager 已暴露到全域，可使用: window.__EYESTRIKE_DEBUG__");
97	            log("   - 下載資料: window.__EYESTRIKE_DEBUG__.DownloadLastSpinData()");
98	            log("   - 上傳資料: window.__EYESTRIKE_DEBUG__.UploadAndLoadSpinData()");
99	            log("   - 快捷鍵: Ctrl+Alt+D 下載資料 | Ctrl+Alt+U 上傳資料");
100	        }
101	    }
102	
103	    /**
104	     * @ch 從 window 移除暴露
105	     */
106	    private RemoveFromWindow(): void {
107	        if (typeof window !== 'undefined') {
108	            delete (window as any)['__EYESTRIKE_DEBUG__'];
109	        }
110	    }
111	
112	    //#endregion 視窗暴露
113	
114	    //#region 鍵盤事件
115	
116	    /**
117	     * @ch 註冊鍵盤事件
118	     */
119	    private RegisterKeyboardEvents(): void {
120	        input.on(Input.EventType.KEY_DOWN, this.OnKeyDown, this);
121	        input.on(Input.EventType.KEY_UP, this.OnKeyUp, this);
122	    }
123	
124	    /**
125	     * @ch 取消註冊鍵盤事件
126	     */
127	    private UnregisterKeyboardEvents(): void {
128	        input.off(Input.EventType.KEY_DOWN, this.OnKeyDown, this);
129	        input.off(Input.EventType.KEY_UP, this.OnKeyUp, this);
130	    }
131	
132	    /**
133	     * @ch 按鍵按下事件
134	     */
135	    private OnKeyDown(event: EventKeyboard): void {
136	        // 追蹤 Ctrl 鍵
137	        if (event.keyCode === KeyCode.CTRL_LEFT || event.keyCode === KeyCode.CTRL_RIGHT) {
138	            this.m_isCtrlPressed = true;
139	        }
140	        // 追蹤 Alt 鍵
141	        if (event.keyCode === KeyCode.ALT_LEFT || event.keyCode === KeyCode.ALT_RIGHT) {
142	            this.m_isAltPressed = true;
143	        }
144	
145	        // Ctrl+Alt+D: 下載最後一次 spin 資料
146	        if (event.keyCode === KeyCode.KEY_D && this.m_isCtrlPressed && this.m_isAltPressed) {
147	            this.DownloadLastSpinData();
148	        }
149	
150	        // Ctrl+Alt+U: 上傳並載入 spin 資料
151	        if (event.keyCode === KeyCode.KEY_U && this.m_isCtrlPressed && this.m_isAltPressed) {
152	            this.UploadAndLoadSpinData();
153	        }
154	
155	        // Ctrl+Alt+P: 顯示/隱藏性能分析器
156	        if (event.keyCode === KeyCode.KEY_P && this.m_isCtrlPressed && this.m_isAltPressed) {
157	            this.ShowProfiler();
158	        }
159	    }
160	
161	    /**
162	     * @ch 按鍵釋放事件
163	     */
164	    private OnKeyUp(event: EventKeyboard): void {
165	        // 釋放 Ctrl 鍵
166	        if (event.keyCode === KeyCode.CTRL_LEFT || event.keyCode === KeyCode.CTRL_RIGHT) {
167	            this.m_isCtrlPressed = false;
168	        }
169	        // 釋放 Alt 鍵
170	        if (event.keyCode === KeyCode.ALT_LEFT || event.keyCode === KeyCode.ALT_RIGHT) {
171	            this.m_isAltPressed = false;
172	        }
173	    }
174	
175	    //#endregion 鍵盤事件
176	
177	    //#region 事件監聽
178	    /**
179	     * @ch 註冊事件監聽器
180	     */
181	    private RegisterEventListeners(): void {
182	        eventManager.Register(DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED, this);
183	        eventManager.Register(DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA, this);
184	        eventManager.Register(DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA, this);
185	    }
186	
187	    /**
188	     * @ch 取消註冊事件監聽器
189	     */
190	    private UnregisterEventListeners(): void {
191	        eventManager.UnRegister(DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED, this);
192	        eventManager.UnRegister(DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA, this);
193	        eventManager.UnRegister(DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA, this);
194	    }
195	
196	    /**
197	     * @ch 事件處理
198	     * @param event 事件名稱
199	     * @param args 事件參數
200	     */
201	    OnEvent(event: string, ...args: any[]): void {
202	        if ( !this.IsDebugEnvironment() )
203	        {
204	            return;
205	        }
206	
207	        switch (event) {
208	            case DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED:
209	                // 參數: (data: Uint8Array)
210	                if (args.length > 0 ) {
211	                    this.SaveSpinData(args[0]);
212	                } else {
213	                    error("❌ SPIN_DATA_RECEIVED 事件接收到無效的資料格式");
214	                }
215	                break;
216	
217	            case DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA:
218	                if (typeof args[0] === "function") {
219	                    args[0](this.m_pendingSpinData);
220	                }
221	                break;
222	                
223	            case DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA:
224	                this.m_pendingSpinData = null;
225	                break;
226	        }
227	    }
228	    //#endregion 事件監聽
229	
230	    //#region 公開 API
231	
232	    /**
233	     * @ch 儲存 Spin 資料 (私有方法，透過事件觸發)
234	     * @param data Spin 原始資料
235	     */
236	    private SaveSpinData(data: Uint8Array): void {
237	        if (!this.IsDebugEnvironment()) {
238	            return;
239	        }
240	        this.m_lastSpinData = data;
241	        log(`💾 已儲存 Spin 資料: ${data.length} bytes`);
242	    }
243	
244	    /**
245	     * @ch 下載最後一次 spin 的原始資料為 .bin 檔案
246	     * @description 可在瀏覽器控制台手動調用：window.__EYESTRIKE_DEBUG__.DownloadLastSpinData()
247	     */
248	    public DownloadLastSpinData(): void {
249	        if (!this.IsDebugEnvironment()) {
250	            log("⚠️ 除錯工具已停用");
251	            return;
252	        }
253	
254	        if (!this.m_lastSpinData) {
255	            log("⚠️ 尚無 spin 資料可供下載");
256	            return;
257	        }
258	
259	        try {
260	            // 產生時間戳記檔名
261	            const now = new Date();
262	            const timestamp = now.getFullYear().toString() +
263	                (now.getMonth() + 1).toString().padStart(2, '0') +
264	                now.getDate().toString().padStart(2, '0') + '_' +
265	                now.getHours().toString().padStart(2, '0') +
266	                now.getMinutes().toString().padStart(2, '0') +
267	                now.getSeconds().toString().padStart(2, '0');
268	            const filename = `spin_data_${timestamp}.bin`;
269	
270	            // 將 Uint8Array 轉換為 Blob
271	            const dataArray = new Uint8Array(this.m_lastSpinData);
272	            const blob = new Blob([dataArray], { type: 'application/octet-stream' });
273	
274	            // 建立下載連結
275	            const url = URL.createObjectURL(blob);
276	            const link = document.createElement('a');
277	            link.href = url;
278	            link.download = filename;
279	
280	            // 觸發下載
281	            document.body.appendChild(link);
282	            link.click();
283	
284	            // 清理
285	            document.body.removeChild(link);
286	            URL.revokeObjectURL(url);
